    public override object parseMarket(object market)
    {
        //
        //     {
        //       "name": "BTC-USD",
        //       "uiName": "BTC-USD",
        //       "category": "Crypto",
        //       "subCategory": "L1",
        //       "assetName": "BTC",
        //       "assetPrecision": 5,
        //       "collateralAssetName": "USD",
        //       "collateralAssetPrecision": 6,
        //       "description": "Bitcoin",
        //       "active": true,
        //       "status": "ACTIVE",
        //       "marketStats": { ... },
        //       "tradingConfig": {
        //         "minOrderSize": "0.0001",
        //         "minOrderSizeChange": "0.00001",
        //         "minPriceChange": "1",
        //         "maxMarketOrderValue": "3000000",
        //         "maxLimitOrderValue": "15000000",
        //         "maxPositionValue": "60000000",
        //         "maxLeverage": "50.00",
        //         "hourlyFundingRateCap": "0.25",
        //         "maxNumOrders": "200",
        //         "limitPriceCap": "0.05",
        //         "limitPriceFloor": "0.05",
        //         "riskFactorConfig": [
        //           {
        //             "upperBound": "4000000",
        //             "riskFactor": "0.02",
        //             "isAvailableForUsers": true
        //           }
        //         ]
        //       },
        //       "l2Config": { ... },
        //       "visibleOnUi": true,
        //       "createdAt": 1752829532673
        //     }
        //
        object tradingConfig = this.safeDict(market, "tradingConfig", new Dictionary<string, object>() {});
        object marketId = this.safeString(market, "name");
        object baseId = this.safeString(market, "assetName");
        if (isTrue(isGreaterThanOrEqual(getIndexOf(baseId, "SPOT"), 0)))
        {
            baseId = ((string)baseId).Replace((string)"SPOT", (string)"");
        }
        object quoteId = this.safeString(market, "collateralAssetName");
        object bs = this.safeCurrencyCode(baseId);
        object quote = this.safeCurrencyCode(quoteId);
        if (isTrue(isEqual(quoteId, "USD")))
        {
            quote = "USDC";
        }
        object status = this.safeString(market, "status");
        object active = (isEqual(status, "ACTIVE"));
        object amountPrecision = this.safeNumber(tradingConfig, "minOrderSizeChange");
        object pricePrecision = this.safeNumber(tradingConfig, "minPriceChange");
        object maxLeverage = this.safeNumber(tradingConfig, "maxLeverage");
        object minAmount = this.safeNumber(tradingConfig, "minOrderSize");
        object maxCost = this.safeNumber(tradingConfig, "maxLimitOrderValue");
        object created = this.safeInteger(market, "createdAt");
        object settleId = null;
        object settle = null;
        object symbol = add(add(bs, "/"), quote);
        object isSpot = false;
        object type = this.safeStringLower(market, "type");
        object contractSize = null;
        object linear = null;
        object inverse = null;
        if (isTrue(isEqual(type, "spot")))
        {
            isSpot = true;
        } else
        {
            type = "swap";
            settleId = quoteId;
            settle = quote;
            symbol = add(symbol, add(":", settle));
            contractSize = this.parseNumber("1");
            linear = true;
            inverse = false;
        }
        return this.safeMarketStructure(new Dictionary<string, object>() {
            { "id", marketId },
            { "symbol", symbol },
            { "base", bs },
            { "quote", quote },
            { "settle", settle },
            { "baseId", baseId },
            { "quoteId", quoteId },
            { "settleId", settleId },
            { "type", type },
            { "spot", isSpot },
            { "margin", false },
            { "swap", !isTrue(isSpot) },
            { "future", false },
            { "option", false },
            { "active", active },
            { "contract", !isTrue(isSpot) },
            { "linear", linear },
            { "inverse", inverse },
            { "taker", this.safeNumber(this.fees, "taker") },
            { "maker", this.safeNumber(this.fees, "maker") },
            { "contractSize", contractSize },
            { "expiry", null },
            { "expiryDatetime", null },
            { "strike", null },
            { "optionType", null },
            { "precision", new Dictionary<string, object>() {
                { "amount", amountPrecision },
                { "price", pricePrecision },
            } },
            { "limits", new Dictionary<string, object>() {
                { "leverage", new Dictionary<string, object>() {
                    { "min", this.parseNumber("1") },
                    { "max", maxLeverage },
                } },
                { "amount", new Dictionary<string, object>() {
                    { "min", minAmount },
                    { "max", null },
                } },
                { "price", new Dictionary<string, object>() {
                    { "min", null },
                    { "max", null },
                } },
                { "cost", new Dictionary<string, object>() {
                    { "min", null },
                    { "max", maxCost },
                } },
            } },
            { "created", created },
            { "info", market },
        });
