            { "deposit", true },
            { "withdraw", true },
            { "precision", Math.Pow(Convert.ToDouble(10), Convert.ToDouble(multiply(precision, -1))) },
            { "type", "other" },
            { "margin", this.safeBool(currency, "canBeUsedAsCollateral") },
            { "info", currency },
        });
    }

